module TopModule (
    input clk,
    input reset,
    input [31:0] in,
    output reg [31:0] out
);

reg [31:0] prev_in;

always @(posedge clk) begin
    if (reset) begin
        out <= 32'b0;
        prev_in <= 32'b0;
    end else begin
        // Detect 1->0 transitions: prev_in[i]==1 && in[i]==0
        out <= out | (prev_in & ~in);
        prev_in <= in;
    end
end

endmodule

